(function(global){
  function createSnowyAnnotationComponent(Vue,antd,dayjs){
    const {computed,nextTick,onBeforeUnmount,onMounted,reactive,ref,watch}=Vue;
    return{
      name:'SnowyAnnotationLayer',
      props:{page:Object},
      setup(props){
        const storageKey='snowy-prototype-kit:annotations:'+(location.pathname||document.title);
        const embedded=(()=>{try{return JSON.parse(document.getElementById('snowy-annotation-state')?.textContent||'{}')}catch{return{}}})();
        const local=(()=>{try{return JSON.parse(localStorage.getItem(storageKey)||'{}')}catch{return{}}})();
        const state=reactive(local.savedAt&&(!embedded.savedAt||local.savedAt>=embedded.savedAt)?local:embedded);
        if(!state.pages)state.pages={};
        const baselines=new Map();
        const enabled=ref(false),collapsed=ref(false),commentOpen=ref(false),commentText=ref(''),commentNodeKey=ref(''),commentStyle=reactive({left:'20px',top:'70px'}),editorOpen=ref(false),editor=reactive({id:'',title:'',summary:'',detail:'',baseline:false}),editorSnapshot=ref(''),requirementOpen=ref(false),requirementEditing=ref(false),requirementDraft=ref(''),requirementSnapshot=ref('');
        let hoverOutline=null,selectedOutline=null,selectedElement=null;
        const pageState=()=>state.pages[props.page.id];
        function clone(value){return JSON.parse(JSON.stringify(value))}
        function ensurePage(){
          if(!props.page)return;
          if(!baselines.has(props.page.id))baselines.set(props.page.id,clone(props.page.annotations||[]));
          if(!state.pages[props.page.id])state.pages[props.page.id]={annotations:clone(props.page.annotations||[]),requirement:props.page.requirement||'',hiddenBaselineIds:[]};
          const current=state.pages[props.page.id];
          if(!Array.isArray(current.annotations))current.annotations=[];
          if(!Array.isArray(current.hiddenBaselineIds))current.hiddenBaselineIds=[];
          if(typeof current.requirement!=='string')current.requirement=props.page.requirement||'';
        }
        const annotations=computed(()=>{ensurePage();return pageState()?.annotations||[]});
        const editorDirty=computed(()=>JSON.stringify({title:editor.title,summary:editor.summary,detail:editor.detail})!==editorSnapshot.value);
        const requirementDirty=computed(()=>requirementDraft.value!==requirementSnapshot.value);
        function persist(){state.savedAt=new Date().toISOString();localStorage.setItem(storageKey,JSON.stringify(state));return clone(state)}
        function removeOverlay(){hoverOutline?.remove();selectedOutline?.remove();hoverOutline=null;selectedOutline=null}
        function visibleRect(el){const rect=el.getBoundingClientRect();const left=Math.max(0,rect.left),top=Math.max(0,rect.top),right=Math.min(innerWidth,rect.right),bottom=Math.min(innerHeight,rect.bottom);return right>left&&bottom>top?{left,top,right,bottom,width:right-left,height:bottom-top}:null}
        function outline(el,selected=false){const rect=visibleRect(el);if(!rect)return;let node=selected?selectedOutline:hoverOutline;if(!node){node=document.createElement('div');node.className='snowy-comment-outline';document.body.appendChild(node);if(selected)selectedOutline=node;else hoverOutline=node}Object.assign(node.style,{left:(rect.left-2)+'px',top:(rect.top-2)+'px',width:(rect.width+4)+'px',height:(rect.height+4)+'px',display:'block'})}
        function targetOf(event){return event.target.closest?.('[data-node-key]')||null}
        function hover(event){if(!enabled.value||commentOpen.value)return;const target=targetOf(event);if(!target){hoverOutline&&(hoverOutline.style.display='none');return}outline(target)}
        function select(event){if(!enabled.value||commentOpen.value)return;const target=targetOf(event);if(!target)return;event.preventDefault();event.stopPropagation();selectedElement=target;commentNodeKey.value=target.dataset.nodeKey;outline(target,true);commentText.value='';commentStyle.left=Math.min(innerWidth-360,Math.max(8,event.clientX+12))+'px';commentStyle.top=Math.min(innerHeight-90,Math.max(8,event.clientY+12))+'px';commentOpen.value=true;nextTick(()=>document.querySelector('.snowy-comment-popover textarea')?.focus())}
        function cancelComment(){commentOpen.value=false;commentText.value='';commentNodeKey.value='';selectedElement=null;selectedOutline?.remove();selectedOutline=null}
        function saveComment(){const text=commentText.value.trim();if(!text)return;const list=annotations.value;list.push({id:`${props.page.id}-user-${Date.now()}`,index:list.reduce((n,item)=>Math.max(n,Number(item.index)||0),0)+1,title:'注释',summary:text,detail:'',nodeKey:commentNodeKey.value,baseline:false});persist();cancelComment();renderPins();antd.message.success('注释已添加')}
        function openEditor(note){Object.assign(editor,clone(note));editorSnapshot.value=JSON.stringify({title:editor.title,summary:editor.summary,detail:editor.detail});editorOpen.value=true}
        function saveEditor(){const note=annotations.value.find(item=>item.id===editor.id);if(note)Object.assign(note,{title:editor.title.trim()||'注释',summary:editor.summary.trim(),detail:editor.detail.trim()});persist();editorSnapshot.value=JSON.stringify({title:editor.title,summary:editor.summary,detail:editor.detail});editorOpen.value=false;renderPins()}
        function deleteEditor(){const list=annotations.value,index=list.findIndex(item=>item.id===editor.id),base=(baselines.get(props.page.id)||[]).find(item=>item.id===editor.id);if(index<0)return;if(base&&JSON.stringify(list[index])!==JSON.stringify(base))list.splice(index,1,clone(base));else{list.splice(index,1);if(base&&!pageState().hiddenBaselineIds.includes(base.id))pageState().hiddenBaselineIds.push(base.id)}persist();editorOpen.value=false;renderPins()}
        function deleteAll(){state.pages[props.page.id].annotations=clone(baselines.get(props.page.id)||[]);state.pages[props.page.id].hiddenBaselineIds=[];persist();editorOpen.value=false;renderPins();antd.message.success('当前页面标注已恢复初始状态')}
        function openRequirement(){ensurePage();requirementDraft.value=pageState().requirement;requirementSnapshot.value=requirementDraft.value;requirementEditing.value=false;requirementOpen.value=true}
        function saveRequirement(){pageState().requirement=requirementDraft.value.trim();persist();requirementSnapshot.value=pageState().requirement;requirementEditing.value=false}
        function cancelRequirement(){requirementDraft.value=requirementSnapshot.value;requirementEditing.value=false}
        function positionPin(pin,target){const rect=visibleRect(target);if(!rect){pin.style.display='none';return}pin.style.display='grid';pin.style.left=Math.max(4,rect.right-30)+'px';pin.style.top=Math.max(4,rect.top)+'px'}
        function renderPins(){document.querySelectorAll('.snowy-comment-pin').forEach(node=>node.remove());for(const note of annotations.value){if(!note.nodeKey||pageState().hiddenBaselineIds.includes(note.id))continue;const target=document.querySelector(`[data-node-key="${CSS.escape(note.nodeKey)}"]`);if(!target)continue;const pin=document.createElement('button');pin.type='button';pin.className='snowy-comment-pin'+(note.baseline===false?' user':'');pin.textContent=note.index;pin.__target=target;pin.onclick=event=>{event.stopPropagation();openEditor(note)};document.body.appendChild(pin);positionPin(pin,target)}}
        function reposition(){document.querySelectorAll('.snowy-comment-pin').forEach(pin=>positionPin(pin,pin.__target));if(selectedElement)outline(selectedElement,true)}
        function saveAsHtml(){cancelComment();const snapshot=persist();const doc=new DOMParser().parseFromString('<!doctype html>\n'+document.documentElement.outerHTML,'text/html');doc.querySelectorAll('.snowy-comment-pin,.snowy-comment-outline,.snowy-comment-mask,.snowy-comment-popover').forEach(node=>node.remove());const app=doc.getElementById('app');if(app)app.innerHTML='';doc.getElementById('snowy-annotation-state').textContent=JSON.stringify(snapshot).replace(/</g,'\\u003c');const blob=new Blob(['<!doctype html>\n'+doc.documentElement.outerHTML],{type:'text/html;charset=utf-8'});const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=`snowy-prototype-${dayjs().format('YYYYMMDD-HHmmss')}.html`;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),1000)}
        function toggle(){enabled.value=!enabled.value;if(!enabled.value){cancelComment();removeOverlay()}}
        watch(()=>props.page?.id,()=>{ensurePage();cancelComment();nextTick(renderPins)},{immediate:true});
        onMounted(()=>{document.addEventListener('mouseover',hover,true);document.addEventListener('click',select,true);window.addEventListener('scroll',reposition,true);window.addEventListener('resize',reposition);nextTick(renderPins)});
        onBeforeUnmount(()=>{document.removeEventListener('mouseover',hover,true);document.removeEventListener('click',select,true);window.removeEventListener('scroll',reposition,true);window.removeEventListener('resize',reposition);removeOverlay();document.querySelectorAll('.snowy-comment-pin').forEach(node=>node.remove())});
        return{enabled,collapsed,commentOpen,commentText,commentStyle,editorOpen,editor,editorDirty,requirementOpen,requirementEditing,requirementDraft,requirementDirty,toggle,cancelComment,saveComment,saveEditor,deleteEditor,deleteAll,openRequirement,saveRequirement,cancelRequirement,saveAsHtml};
      },
      template:`<div :class="{'snowy-annotation-cursor':enabled}"><div class="snowy-annotation-toolbar" :class="{collapsed}"><button class="snowy-annotation-tool icon" @click="collapsed=!collapsed" :title="collapsed?'展开':'隐藏'">⌃</button><template v-if="!collapsed"><button class="snowy-annotation-tool" :class="{active:enabled}" @click="toggle">◉ {{enabled?'关闭标注':'开启标注'}}</button><button class="snowy-annotation-tool" @click="openRequirement">▤ 页面需求</button><button class="snowy-annotation-tool" @click="saveAsHtml">▣ 另存为</button><button class="snowy-annotation-tool danger" @click="deleteAll">⌫ 全部删除</button></template></div><div v-if="commentOpen" class="snowy-comment-mask" @click="cancelComment"></div><div v-if="commentOpen" class="snowy-comment-popover" :class="{multiline:commentText.includes('\\n')}" :style="commentStyle" @click.stop><div class="snowy-comment-input"><button class="snowy-annotation-tool icon" @click="cancelComment">×</button><a-textarea v-model:value="commentText" :auto-size="{minRows:1,maxRows:4}" placeholder="添加评论..."/><button class="snowy-comment-send" :disabled="!commentText.trim()" @click="saveComment">↑</button></div></div><a-modal v-model:open="editorOpen" :title="'注释 '+editor.index" :z-index="2300"><a-form layout="vertical"><a-form-item label="标题"><a-input v-model:value="editor.title"/></a-form-item><a-form-item label="内容"><a-textarea v-model:value="editor.summary" :auto-size="{minRows:2,maxRows:8}"/></a-form-item><a-form-item v-if="editor.detail" label="详细说明"><a-textarea v-model:value="editor.detail" :auto-size="{minRows:2,maxRows:8}"/></a-form-item></a-form><template #footer><div style="display:flex;justify-content:space-between"><a-button danger @click="deleteEditor">删除</a-button><a-space><a-button @click="editorOpen=false">取消</a-button><a-button v-if="editorDirty" type="primary" @click="saveEditor">保存</a-button></a-space></div></template></a-modal><a-drawer v-model:open="requirementOpen" :title="page.title+' - 整体需求说明'" :z-index="2200" width="520"><a-textarea v-if="requirementEditing" v-model:value="requirementDraft" :auto-size="{minRows:12,maxRows:24}"/><div v-else class="snowy-annotation-preview">{{requirementDraft||'暂无整体需求描述'}}<button class="snowy-inline-edit" @click="requirementEditing=true">✎</button></div><template #footer><div style="display:flex;justify-content:flex-end;gap:8px"><a-button v-if="requirementEditing" @click="cancelRequirement">取消</a-button><a-button v-else @click="requirementOpen=false">关闭</a-button><a-button v-if="requirementDirty" type="primary" @click="saveRequirement">保存</a-button></div></template></a-drawer></div>`
    };
  }
  global.SnowyPrototypeKit=Object.assign(global.SnowyPrototypeKit||{},{createSnowyAnnotationComponent});
})(window);
